def _advertising_payload(limited_disc=False, br_edr=False, name=None, services=None, appearance=0):
    """Generate a BLE advertising payload."""
    payload = bytearray()

    def _append(adv_type, value):
        nonlocal payload
        payload += struct.pack("BB", len(value) + 1, adv_type) + value

    _append(
        _ADV_TYPE_FLAGS,
        struct.pack("B", (0x01 if limited_disc else 0x02) + (0x18 if br_edr else 0x04)),
    )

    if name:
        _append(_ADV_TYPE_NAME, name.encode())

    if services:
        for uuid in services:
            b = bytes(uuid)
            if len(b) == 2:
                _append(_ADV_TYPE_UUID16_COMPLETE, b)
            elif len(b) == 16:
                _append(_ADV_TYPE_UUID128_COMPLETE, b)

    if appearance:
        _append(_ADV_TYPE_APPEARANCE, struct.pack("<H", appearance))

    return payload


class SensorManager:
    """Manages sensor readings from the ESP32."""

    def __init__(self):
        # Internal temperature sensor (if available)
        self._temp_offset = 0.0
